package genxsolution.vms.vmsbackend.vehicle_management.vehicle_daily_summary.service;
import genxsolution.vms.vmsbackend.vehicle_management.exception.VehicleResourceNotFoundException; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_daily_summary.dto.*; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_daily_summary.mapper.VehicleDailySummaryMapper; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_daily_summary.repository.VehicleDailySummaryRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class VehicleDailySummaryService { private final VehicleDailySummaryRepository repository; private final VehicleDailySummaryMapper mapper; public VehicleDailySummaryService(VehicleDailySummaryRepository repository,VehicleDailySummaryMapper mapper){this.repository=repository;this.mapper=mapper;} public List<VehicleDailySummaryResponse> list(UUID companyId){ return repository.findAll(companyId).stream().map(mapper::toResponse).toList(); } public VehicleDailySummaryResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new VehicleResourceNotFoundException("VehicleDailySummary", id.toString())); } public VehicleDailySummaryResponse create(VehicleDailySummaryUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public VehicleDailySummaryResponse update(UUID id,VehicleDailySummaryUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new VehicleResourceNotFoundException("VehicleDailySummary", id.toString())); } public void delete(UUID id){ if(!repository.delete(id)) throw new VehicleResourceNotFoundException("VehicleDailySummary", id.toString()); } }
